#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <omp.h>
#include <string.h>
#include "timer.h"

#define BLOCK_SIZE 256
#define STR_SIZE 256
#define DEVICE 0
#define HALO 1

void run(int argc, char** argv);

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9
int pyramid_height;

void init(int argc, char** argv)
{
    if(argc==4){
        cols = atoi(argv[1]);
        rows = atoi(argv[2]);
        pyramid_height = atoi(argv[3]);
    } else {
        printf("Usage: dynproc row_len col_len pyramid_height\n");
        exit(0);
    }
    data = new int[rows*cols];
    wall = new int*[rows];
    for(int n=0; n<rows; n++)
        wall[n] = data + cols*n;
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            wall[i][j] = rand() % 10;
        }
    }
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("%d ", wall[i][j]);
        }
        printf("\n");
    }
#endif
}

void fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);
}

#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x)
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

void dynproc_kernel_omp(
    int iteration,
    int *gpuWall,
    int *gpuSrc,
    int *gpuResults,
    int cols,
    int rows,
    int startStep,
    int border,
    int blockCols)
{
    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < blockCols; bx++) {
        int prev[BLOCK_SIZE];
        int res[BLOCK_SIZE];
        bool computed_arr[BLOCK_SIZE];

        int small_block_cols = BLOCK_SIZE - iteration * HALO * 2;
        int blkX = small_block_cols * bx - border;
        int blkXmax = blkX + BLOCK_SIZE - 1;

        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

        // Load prev from gpuSrc
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int xidx = blkX + tx;
            if (IN_RANGE(xidx, 0, cols-1)) {
                prev[tx] = gpuSrc[xidx];
            } else {
                prev[tx] = 0;
            }
            computed_arr[tx] = false;
            res[tx] = 0;
        }

        for (int i = 0; i < iteration; i++) {
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                computed_arr[tx] = false;
            }

            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                bool isValid = IN_RANGE(tx, validXmin, validXmax);
                if (IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid) {
                    int W = tx - 1;
                    int E = tx + 1;
                    W = (W < validXmin) ? validXmin : W;
                    E = (E > validXmax) ? validXmax : E;

                    computed_arr[tx] = true;
                    int left = prev[W];
                    int up = prev[tx];
                    int right = prev[E];
                    int shortest = MIN(left, up);
                    shortest = MIN(shortest, right);
                    int xidx = blkX + tx;
                    int index = cols * (startStep + i) + xidx;
                    res[tx] = shortest + gpuWall[index];
                }
            }

            if (i == iteration - 1)
                break;

            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                if (computed_arr[tx])
                    prev[tx] = res[tx];
            }
        }

        // Write results back
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int xidx = blkX + tx;
            if (computed_arr[tx]) {
                gpuResults[xidx] = res[tx];
            }
        }
    }
}

int calc_path(int *gpuWall, int *gpuResult[2], int rows, int cols,
              int pyramid_height, int blockCols, int borderCols)
{
    int src = 1, dst = 0;
    for (int t = 0; t < rows-1; t += pyramid_height) {
        int temp = src;
        src = dst;
        dst = temp;

        int iter = MIN(pyramid_height, rows-t-1);
        dynproc_kernel_omp(
            iter,
            gpuWall,
            gpuResult[src],
            gpuResult[dst],
            cols, rows, t, borderCols, blockCols);
    }
    return dst;
}

int main(int argc, char** argv)
{
    run(argc, argv);
    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    int borderCols = (pyramid_height) * HALO;
    int smallBlockCol = BLOCK_SIZE - (pyramid_height) * HALO * 2;
    int blockCols = cols / smallBlockCol + ((cols % smallBlockCol == 0) ? 0 : 1);

    printf("pyramidHeight: %d\ngridSize: [%d]\nborder:[%d]\nblockSize: %d\nblockGrid:[%d]\ntargetBlock:[%d]\n",
           pyramid_height, cols, borderCols, BLOCK_SIZE, blockCols, smallBlockCol);

    int *gpuWall, *gpuResult[2];
    int size = rows * cols;

    gpuResult[0] = new int[cols];
    gpuResult[1] = new int[cols];
    memcpy(gpuResult[0], data, sizeof(int) * cols);
    gpuWall = new int[size - cols];
    memcpy(gpuWall, data + cols, sizeof(int) * (size - cols));

    unsigned long long kernel_cycles = 0;
    startCycle();

    int final_ret = calc_path(gpuWall, gpuResult, rows, cols,
                              pyramid_height, blockCols, borderCols);

    stopCycle(kernel_cycles);

    memcpy(result, gpuResult[final_ret], sizeof(int) * cols);

    printf("timer: %llu\n", kernel_cycles);

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
        printf("%d ", data[i]);
    printf("\n");
    for (int i = 0; i < cols; i++)
        printf("%d ", result[i]);
    printf("\n");
#endif

    delete [] gpuWall;
    delete [] gpuResult[0];
    delete [] gpuResult[1];
    delete [] data;
    delete [] wall;
    delete [] result;
}
